// Postcondition shape: `H ==> det_equal` where
//   H = HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
//     && HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
// and
//   det_equal := r1.0 == r2.0
//              && (r1.1)@.view() == (r2.1)@.view()       // recvs/clocks/sends/ios match pointwise
//              && post1_self_@ == post2_self_@
//              && post1_netc.view() == post2_netc.view().  // history+end_point match
//
// Prior attempt's structural flaw: it did its trigger work inside a top-level
// `if H { ... }`, but in Verus the resulting facts don't propagate out to the
// function postcondition obligation — verus checks `H ==> det_equal` afresh at
// the function boundary.  The repair is to package the entire bridge inside an
// `assert(H ==> det_equal) by { ... }` so Verus picks up the implication as a
// first-class fact, and finish the `by`-body with an explicit
// `assert(det_equal(...))` so the bridge is forced.

let er1: EventResults = (r1.1)@;
let er2: EventResults = (r2.1)@;

assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    && HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> det_host_noreceive_noclock_next_equal(r1, r2, post1_self_@, post2_self_@, post1_netc, post2_netc)
) by {
    if HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        && HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    {
        let ok1: bool = r1.0;
        let ok2: bool = r2.0;

        // ---- Materialise every conjunct of next_ensures on both runs.
        // These are direct restatements that Verus discharges from H.
        assert(ok1 == post1_netc.ok());
        assert(ok2 == post2_netc.ok());
        assert(er1.well_typed_events());
        assert(er2.well_typed_events());
        assert((ok1 || er1.sends.len() > 0) ==>
            post1_netc.history() == pre_netc.history() + er1.event_seq());
        assert((ok2 || er2.sends.len() > 0) ==>
            post2_netc.history() == pre_netc.history() + er2.event_seq());

        // ---- Re-fire the `forall|i|` quantifiers from well_typed_events
        // with matching trigger shapes across the two runs.  This is the
        // quantifier-instantiation gap behind the file-level `unknown`.
        assert(forall|i: int| 0 <= i < er1.recvs.len() ==> er1.recvs[i] is Receive);
        assert(forall|i: int| 0 <= i < er2.recvs.len() ==> er2.recvs[i] is Receive);
        assert(forall|i: int| 0 <= i < er1.clocks.len() ==>
            er1.clocks[i] is ReadClock || er1.clocks[i] is TimeoutReceive);
        assert(forall|i: int| 0 <= i < er2.clocks.len() ==>
            er2.clocks[i] is ReadClock || er2.clocks[i] is TimeoutReceive);
        assert(forall|i: int| 0 <= i < er1.sends.len() ==> er1.sends[i] is Send);
        assert(forall|i: int| 0 <= i < er2.sends.len() ==> er2.sends[i] is Send);
        assert(er1.clocks.len() <= 1);
        assert(er2.clocks.len() <= 1);

        // ---- event_seq unfolds to a triple-concat; pin it on both runs so
        // the EventResultsView field-by-field comparison shares a trigger.
        assert(er1.event_seq() == er1.recvs + er1.clocks + er1.sends);
        assert(er2.event_seq() == er2.recvs + er2.clocks + er2.sends);

        // ---- ok-gated conjuncts of next_ensures (per run).  These pin
        // event_seq == ios and the history delta, and bring in the
        // abstract-step `Self::next` predicate plus the `invariants` link
        // `post*_self_@.constants.me == post*_netc.my_end_point()`.
        if ok1 {
            assert(post1_self_.invariants(&post1_netc.my_end_point()));
            assert(HostState::next(pre_self_@, post1_self_@, er1.ios));
            assert(er1.event_seq() == er1.ios);
            assert(post1_self_@.constants == pre_self_@.constants);
            assert(post1_self_@.constants.me == post1_netc.my_end_point());
            assert(post1_netc.history() == pre_netc.history() + er1.ios);
        }
        if ok2 {
            assert(post2_self_.invariants(&post2_netc.my_end_point()));
            assert(HostState::next(pre_self_@, post2_self_@, er2.ios));
            assert(er2.event_seq() == er2.ios);
            assert(post2_self_@.constants == pre_self_@.constants);
            assert(post2_self_@.constants.me == post2_netc.my_end_point());
            assert(post2_netc.history() == pre_netc.history() + er2.ios);
        }

        // ---- Case-split on (ok1, ok2) and, in each branch, force the
        // pointwise/extensional equalities that det_equal demands.
        if ok1 && ok2 {
            assert(ok1 == ok2);

            // Both ios are anchored at the same pre-history tail.
            assert(post1_netc.history() == pre_netc.history() + er1.ios);
            assert(post2_netc.history() == pre_netc.history() + er2.ios);

            // event_seq triple-concat is a common form on both sides.
            assert(er1.recvs + er1.clocks + er1.sends == er1.ios);
            assert(er2.recvs + er2.clocks + er2.sends == er2.ios);

            // The abstract step shares `pre_self_@.constants` on both runs.
            assert(post1_self_@.constants == post2_self_@.constants);
            assert(post1_self_@.constants.me == post2_self_@.constants.me);
            assert(post1_netc.my_end_point() == post2_netc.my_end_point());
        } else if !ok1 && !ok2 {
            assert(ok1 == ok2);
            assert(!post1_netc.ok());
            assert(!post2_netc.ok());
        } else {
            assert(ok1 != ok2);
        }

        // ---- Final bridge.  If verus can chain the above into
        // det_equal, the implication closes; if not, this assertion
        // localises the actual non-deterministic field for the next
        // round of debugging.
        assert(det_host_noreceive_noclock_next_equal(
            r1, r2, post1_self_@, post2_self_@, post1_netc, post2_netc));
    }
};
